// src/App.jsx
import React from "react";
import Navbar from "./components/Navbar.jsx";
import SummaryCards from "./components/SummaryCards.jsx";
import CostPieChart from "./components/CostPieChart.jsx";
import CostLineChart from "./components/CostLineChart.jsx";
import Suggestions from "./components/Suggestions.jsx";
import mockData from "./data/mockData.jsx";
import "./App.css";

function App() {
  const topService = mockData.services.reduce((a, b) => (a.cost > b.cost ? a : b)).name;

  return (
    <div>
      <Navbar />
      <SummaryCards totalCost={mockData.total_cost} month={mockData.month} topService={topService} />
      <div style={{ display: "flex", justifyContent: "space-around", flexWrap: "wrap" }}>
        <CostPieChart services={mockData.services} />
        <CostLineChart monthlyCosts={mockData.monthly_costs} />
      </div>
      <Suggestions suggestions={mockData.suggestions} />
    </div>
  );
}

export default App;